import{_ as s,o as n,c as e,ak as i}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"典型分布式场景方案","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/scenario/index.md","filePath":"distributed/scenario/index.md","lastUpdated":1774319300000}'),t={name:"distributed/scenario/index.md"};function r(l,a,p,d,c,o){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="典型分布式场景方案" tabindex="-1">典型分布式场景方案 <a class="header-anchor" href="#典型分布式场景方案" aria-label="Permalink to “典型分布式场景方案”">​</a></h1><p>理论学了一大堆，最终还是要落地。</p><p>这一模块，将分布式理论与工程实践结合，讲解真实生产环境中的典型场景：多级缓存、统一认证、文件存储、多机房部署……</p><p><strong>每一个场景，都是前人踩过的坑。</strong></p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>典型场景方案分为六大类：</p><table tabindex="0"><thead><tr><th>章节</th><th>篇数</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/distributed/scenario/unified-auth/index">统一认证与 SSO</a></td><td>5 篇</td><td>Session 共享、Token、JWT、CAS、OAuth2</td></tr><tr><td><a href="/distributed/scenario/multi-level-cache/index">多级缓存架构</a></td><td>6 篇</td><td>本地缓存、Redis、穿透/击穿/雪崩、热点数据</td></tr><tr><td><a href="/distributed/scenario/file-storage/index">分布式文件存储</a></td><td>4 篇</td><td>MinIO、FastDFS、分片上传、CDN</td></tr><tr><td><a href="/distributed/scenario/multi-datacenter/index">多机房与数据同步</a></td><td>4 篇</td><td>同城双活、异地多活、binlog 同步</td></tr><tr><td><a href="/distributed/scenario/flow-control/index">流量控制与弹性策略</a></td><td>5 篇</td><td>全链路限流、削峰、降级、重试风暴</td></tr><tr><td><a href="/distributed/scenario/batch-task/index">数据处理与批任务</a></td><td>4 篇</td><td>分片任务、数据同步、唯一执行、定时任务</td></tr><tr><td><a href="/distributed/scenario/unified-logging/index">统一异常与日志</a></td><td>4 篇</td><td>全局异常、链路追踪、日志聚合、可观测性</td></tr></tbody></table><h2 id="场景与方案对照" tabindex="-1">场景与方案对照 <a class="header-anchor" href="#场景与方案对照" aria-label="Permalink to “场景与方案对照”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌──────────────────┬──────────────────────────────────────┐</span></span>
<span class="line"><span>│ 场景             │ 典型方案                              │</span></span>
<span class="line"><span>├──────────────────┼──────────────────────────────────────┤</span></span>
<span class="line"><span>│ 高并发读          │ 多级缓存 + 热点探测                   │</span></span>
<span class="line"><span>│ 高并发写          │ 消息队列削峰 + 分库分表               │</span></span>
<span class="line"><span>│ 缓存一致性         │ Cache Aside + 延迟双删              │</span></span>
<span class="line"><span>│ 缓存异常          │ 穿透（布隆）、击穿（互斥）、雪崩（打散）│</span></span>
<span class="line"><span>│ 统一认证          │ JWT / Spring Session / CAS           │</span></span>
<span class="line"><span>│ 文件存储          │ MinIO / FastDFS + CDN               │</span></span>
<span class="line"><span>│ 多机房部署         │ 同城双活 / 异地多活 / 单元化         │</span></span>
<span class="line"><span>│ 链路追踪          │ TraceId + MDC / Skywalking           │</span></span>
<span class="line"><span>│ 服务限流          │ Sentinel / 令牌桶 / 滑动窗口           │</span></span>
<span class="line"><span>└──────────────────┴──────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="面试高频问题" tabindex="-1">面试高频问题 <a class="header-anchor" href="#面试高频问题" aria-label="Permalink to “面试高频问题”">​</a></h2><h3 id="q1-如何保证缓存和数据库一致性" tabindex="-1">Q1：如何保证缓存和数据库一致性？ <a class="header-anchor" href="#q1-如何保证缓存和数据库一致性" aria-label="Permalink to “Q1：如何保证缓存和数据库一致性？”">​</a></h3><blockquote><p>「没有完美的方案，只有最适合的方案。 方案一 Cache Aside：读先查缓存、写先更新数据库再删缓存（不是更新缓存！）。 方案二 延迟双删：更新数据库后，延迟一段时间再删除缓存，解决并发时的脏读。 关键是要理解每种方案的一致性级别，不要追求过度的强一致。」</p></blockquote><h3 id="q2-如何设计一个分布式-session-方案" tabindex="-1">Q2：如何设计一个分布式 Session 方案？ <a class="header-anchor" href="#q2-如何设计一个分布式-session-方案" aria-label="Permalink to “Q2：如何设计一个分布式 Session 方案？”">​</a></h3><blockquote><p>「两种思路：Session 共享 vs 无状态 Token。 Session 共享：用 Spring Session + Redis，优点是与传统架构一致，缺点是有状态。 Token 方案：用 JWT，优点是无状态可扩展，缺点是 Token 撤销困难。 大多数互联网场景选 Token，企业内部系统可选 Session。」</p></blockquote><h3 id="q3-如何实现接口幂等" tabindex="-1">Q3：如何实现接口幂等？ <a class="header-anchor" href="#q3-如何实现接口幂等" aria-label="Permalink to “Q3：如何实现接口幂等？”">​</a></h3><blockquote><p>「四种方案：</p><ol><li>Token + Redis：接口防重令牌</li><li>唯一键约束：数据库主键或唯一索引</li><li>状态机：订单状态只能「创建→支付→完成」，不能逆向</li><li>分布式锁：锁住业务 ID 选择依据是业务场景，不是越多越好。」</li></ol></blockquote><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to “学习建议”">​</a></h2><p>场景方案的学习，最重要的是<strong>理解问题的本质</strong>：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. 多级缓存：理解每一层缓存的意义和取舍</span></span>
<span class="line"><span>2. 统一认证：理解 Session 和 Token 的本质区别</span></span>
<span class="line"><span>3. 文件存储：理解对象存储和文件系统的适用场景</span></span>
<span class="line"><span>4. 多机房部署：理解 CAP 理论在工程中的体现</span></span>
<span class="line"><span>5. 流量控制：理解限流的本质是「保护系统」</span></span>
<span class="line"><span>6. 可观测性：理解 Metrics、Tracing、Logging 的关系</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>记住：<strong>场景方案的答案不是唯一的，重要的是理解为什么这样选。</strong></p>`,20)])])}const u=s(t,[["render",r]]);export{h as __pageData,u as default};
